// generar_237_analisis_informe_inteligente.js
// CHIQUI Entre Señales — Análisis reorganizado como informe inteligente
//
// La pantalla Análisis deja de ser una colección de widgets y pasa a
// contar una historia lógica, en este orden:
//
// 1) 🤖 Resumen del período (NUEVO, protagonista arriba) — plantillas
//    inteligentes que interpretan los datos: Estado general (estable /
//    con altibajos / señales a observar, con % de días normales y
//    conteo de síntomas), Seguimientos activos (lesiones en curso) y
//    Recomendación. No es IA remota ni tiene costo: son reglas que
//    arman frases naturales con los datos reales de la mascota.
// 2) 📊 Lo observado este mes — los insights de siempre (título
//    mejorado, antes "Lo que observé este mes"), respaldando con datos
//    lo que dijo el resumen.
// 3) Signos de alerta + Normalidad por categoría — respaldo de datos.
// 4) 📅 Últimos 7 días.
// 5) 📊 Resumen del período (total / verdes / atención / síntomas).
// 6) 🐶 Paseos (solo perros) — MISMA lógica (racha, tiempo del mes),
//    pero el gráfico semanal se compactó mucho (de 64px a ~32px de
//    alto) para que la racha y el tiempo total sean lo protagonista.
// 7) 🔄 Rutinas de cuidado — mismo lenguaje conversacional, pero ahora
//    ordenadas por prioridad (retrasadas y próximas a vencer primero)
//    mostrando solo las 3 más relevantes, con "Ver todas las rutinas
//    (X)" para expandir el resto.
// 8) 📋 Registros recientes — al final, como historial detallado.
//
// Solo reescribe app/analisis/page.tsx. No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_237_analisis_informe_inteligente.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/analisis/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo escrito correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
